#include <vector>
#include <set>
#include <map>
#include <algorithm>

using namespace std;

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    vector<int> parent(c + 1, 0);
    vector<int> rank(c + 1, 1);
    for (int i = 1; i <= c; ++i) {
        parent[i] = i;
    }

    auto find = [&](int x) -> int {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    auto union_op = [&](int x, int y) {
        int root_x = find(x);
        int root_y = find(y);
        if (root_x != root_y) {
            if (rank[root_x] < rank[root_y]) {
                parent[root_x] = root_y;
            } else {
                parent[root_y] = root_x;
                if (rank[root_x] == rank[root_y]) {
                    rank[root_x]++;
                }
            }
        }
    };

    for (const auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        union_op(u, v);
    }

    map<int, multiset<int>> component_multisets;
    vector<bool> active(c + 1, true);

    for (int i = 1; i <= c; ++i) {
        int root = find(i);
        component_multisets[root].insert(i);
    }

    vector<long long> result;

    for (const auto& q : queries) {
        int type = q[0];
        int x = q[1];
        if (type == 1) {
            if (active[x]) {
                result.push_back(x);
            } else {
                int root = find(x);
                if (component_multisets[root].empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*component_multisets[root].begin());
                }
            }
        } else {
            active[x] = false;
            int root = find(x);
            component_multisets[root].erase(x);
        }
    }

    return result;
}

