import java.util.*

fun solve(c: Long, connections: Array<Array<Long>>, queries: Array<Array<Long>>): Array<Long> {
    val parent = IntArray(c.toInt() + 1) { it }
    val rank = IntArray(c.toInt() + 1) { 1 }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int) {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY
            } else {
                parent[rootY] = rootX
                if (rank[rootX] == rank[rootY]) {
                    rank[rootX]++
                }
            }
        }
    }

    for (conn in connections) {
        val u = conn[0].toInt()
        val v = conn[1].toInt()
        union(u, v)
    }

    val componentMap = mutableMapOf<Int, TreeSet<Int>>()
    val active = BooleanArray(c.toInt() + 1) { true }

    for (i in 1..c.toInt()) {
        val root = find(i)
        componentMap.getOrPut(root) { TreeSet<Int>() }.add(i)
    }

    val result = mutableListOf<Long>()

    for (query in queries) {
        val type = query[0].toInt()
        val x = query[1].toInt()
        if (type == 1) {
            if (active[x]) {
                result.add(x.toLong())
            } else {
                val root = find(x)
                val component = componentMap[root] ?: continue
                if (component.isEmpty()) {
                    result.add(-1L)
                } else {
                    result.add(component.first().toLong())
                }
            }
        } else {
            active[x] = false
            val root = find(x)
            val component = componentMap[root] ?: continue
            component.remove(x)
        }
    }

    return result.toLongArray()
}
```

